INSERT INTO `evaluations` VALUES (5,11.75,22.50,16.25,15.75,15.50,0.00,0.00,81.75,'Đề tài đạt yêu cầu về mặt nội dung và hình thức. Tuy nhiên, cần chú ý phân tích sâu hơn ở các ý chính để đạt được kết quả tối ưu trong lần tới.','APPROVED','SUBMITTED',16,10),(6,10.00,17.50,14.75,15.00,15.00,0.00,0.00,72.25,'Đây là một hướng nghiên cứu mới mẻ, thể hiện sự sáng tạo và tinh thần tìm tòi học hỏi cao của sinh viên/giảng viên. Cách tiếp cận vấn đề độc đáo cùng với những đề xuất giải pháp có tính đột phá là điểm nhấn quan trọng của đề tài. Hội đồng khuyến khích tác giả tiếp tục mở rộng nghiên cứu để công bố trên các tạp chí khoa học uy tín.','APPROVED','SUBMITTED',18,10),(7,12.25,25.00,18.25,17.25,16.25,0.00,0.00,89.00,'Đề tài thể hiện sự đầu tư công phu, nghiêm túc với phương pháp nghiên cứu hiện đại và hệ thống số liệu tin cậy. Kết quả đạt được không chỉ có giá trị cao về mặt lý luận mà còn mang tính thực tiễn sâu sắc, có khả năng ứng dụng rộng rãi vào thực tế chuyên môn. Hội đồng đánh giá cao tư duy phản biện và khả năng giải quyết vấn đề triệt để của nhóm tác giả.','APPROVED','SUBMITTED',19,10),(8,9.75,20.75,14.50,15.75,14.75,0.00,0.00,75.50,'Nội dung nghiên cứu bám sát mục tiêu đề ra, cấu trúc logic và trình bày khoa học. Nhóm tác giả đã nắm vững kiến thức nền tảng và có những đóng góp nhất định trong việc làm rõ vấn đề nghiên cứu. Tuy còn một vài hạn chế nhỏ về phạm vi khảo sát, nhưng tổng thể đây là một công trình có chất lượng tốt, đủ điều kiện để nghiệm thu và phát triển thêm.','APPROVED','SUBMITTED',20,10);
/*!40000 ALTER TABLE `evaluations` ENABLE KEYS */;
UNLOCK TABLES;

